# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using System.Collections;
using System.Collections.Generic;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int maxHealth = 100;
    public int currency = 500;
    
    public int baseDamage = 10;
    public int damageMultiplier = 1;
    
    public List<ShopItem> shopItems = new List<ShopItem>();
    
    private void Start()
    {
        InitializeShop();
    }
    
    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
    }
    
    public bool CanAfford(int price)
    {
        return currency >= price;
    }
    
    public void PurchaseItem(int itemIndex)
    {
        if (itemIndex >= 0 && itemIndex < shopItems.Count)
        {
            ShopItem item = shopItems[itemIndex];
            if (CanAfford(item.price))
            {
                currency -= item.price;
                ApplyItemEffect(item);
            }
        }
    }
    
    private void ApplyItemEffect(ShopItem item)
    {
        switch (item.effectType)
        {
            case ShopItem.EffectType.Health:
                health += item.value;
                if (health > maxHealth) health = maxHealth;
                break;
            case ShopItem.EffectType.Damage:
                baseDamage += item.value;
                break;
            case ShopItem.EffectType.Currency:
                currency += item.value;
                break;
        }
    }
    
    private void InitializeShop()
    {
        shopItems.Add(new ShopItem("Health Potion", 50, ShopItem.EffectType.Health, 30));
        shopItems.Add(new ShopItem("Sword Upgrade", 100, ShopItem.EffectType.Damage, 5));
        shopItems.Add(new ShopItem("Gold Coin", 20, ShopItem.EffectType.Currency, 100));
    }
    
    public int CalculateDamage()
    {
        return baseDamage * damageMultiplier;
    }
}

[System.Serializable]
public class ShopItem
{
    public string itemName;
    public int price;
    public EffectType effectType;
    public int value;
    
    public enum EffectType
    {
        Health,
        Damage,
        Currency
    }
    
    public ShopItem(string name, int itemPrice, EffectType type, int itemValue)
    {
        itemName = name;
        price = itemPrice;
        effectType = type;
        value = itemValue;
    }
}